// ── MAIN FETCH HANDLER ────────────────────────────────────────────────
export default {
  async fetch(req, env) {
    try {
      await initDb(env.DB);
    } catch (e) {
      return new Response('DB init error: ' + e.message, { status: 500 });
    }

    const url = new URL(req.url);
    const path = url.pathname.replace(/\/$/, '') || '/';
    const method = req.method.toUpperCase();

    if ((path === '/' || path === '/index.html') && method === 'GET') return html(PUBLIC_HTML);
    if (path === '/api/events' && method === 'GET') return handleApiEvents(env);
    if (path === '/volunteer/signup' && method === 'POST') return handleSignup(req, env);
    if (path.match(/^\/volunteer\/calendar\/\d+$/) && method === 'GET') return handleCalendar(env, path);
    if (path === '/admin/login' && method === 'POST') return handleAdminLogin(req);
    if (path === '/admin' && method === 'GET') {
      if (!isAuthed(req)) return html(LOGIN_HTML);
      return html(ADMIN_HTML);
    }
    if (path.startsWith('/admin/api/')) {
      if (!isAuthed(req)) return json({ error: 'Unauthorized' }, 401);
      return handleAdminApi(req, env, url, method);
    }
    if (path.startsWith('/scheduler')) {
      const ghUrl = 'https://timothystl.github.io/volunteer' + url.pathname + url.search;
      return fetch(ghUrl, { headers: { 'User-Agent': req.headers.get('User-Agent') || '' } });
    }
    return new Response('Not Found', { status: 404 });
  }
};

// ── PUBLIC API: GET /api/events ───────────────────────────────────────
async function handleApiEvents(env) {
  const events = await env.DB.prepare(
    'SELECT * FROM serve_events WHERE hidden=0 ORDER BY sort_order,event_date,id'
  ).all();
  const result = [];
  for (const ev of (events.results || [])) {
    const roles = await env.DB.prepare(
      'SELECT * FROM serve_roles WHERE event_id=? ORDER BY role_date,sort_order,id'
    ).bind(ev.id).all();
    const rolesWithFill = [];
    for (const role of (roles.results || [])) {
      const filled = await env.DB.prepare(
        'SELECT COUNT(*) as n FROM signup_slots WHERE role_id=?'
      ).bind(role.id).first();
      rolesWithFill.push({ ...role, filled_count: filled?.n || 0 });
    }
    result.push({ ...ev, roles: rolesWithFill });
  }
  return json({ events: result });
}

// ── PUBLIC API: POST /volunteer/signup ────────────────────────────────
async function handleSignup(req, env) {
  let data;
  try { data = await req.json(); } catch { return json({ ok: false, error: 'Invalid JSON' }, 400); }
  const name  = (data.name || '').trim();
  const email = (data.email || '').trim();
  if (!name || !email) return json({ ok: false, error: 'Name and email required' }, 400);

  // Validate slot availability for time-slotted signups
  const roleIds = Array.isArray(data.role_ids) ? data.role_ids : [];
  for (const rid of roleIds) {
    const role   = await env.DB.prepare('SELECT slots FROM serve_roles WHERE id=?').bind(rid).first();
    const filled = await env.DB.prepare('SELECT COUNT(*) as n FROM signup_slots WHERE role_id=?').bind(rid).first();
    if (role && role.slots > 0 && (filled?.n || 0) >= role.slots) {
      return json({ ok: false, error: 'One or more selected shifts are now full. Please refresh and try again.' }, 409);
    }
  }

  const r = await env.DB.prepare(
    `INSERT INTO signups (event_id,role_id,ministry,name,email,phone,roles,service,sundays,shirt_wanted,shirt_size,notes)
     VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`
  ).bind(
    data.event_id || null, data.role_id || null,
    data.ministry || '', name, email, data.phone || '',
    JSON.stringify(data.roles || roleIds.map(String)),
    data.service || '', JSON.stringify(data.sundays || []),
    data.shirt_wanted ? 1 : 0, data.shirt_size || '', data.notes || ''
  ).run();
  const signupId = r.meta?.last_row_id;

  for (const rid of roleIds) {
    await env.DB.prepare('INSERT INTO signup_slots (signup_id,role_id) VALUES (?,?)')
      .bind(signupId, rid).run();
  }

  return json({ ok: true, signup_id: signupId });
}

// ── ICAL DOWNLOAD: GET /volunteer/calendar/:id ────────────────────────
async function handleCalendar(env, path) {
  const signupId = parseInt(path.split('/').pop());
  const signup = await env.DB.prepare('SELECT * FROM signups WHERE id=?').bind(signupId).first();
  if (!signup) return new Response('Not found', { status: 404 });

  const slots = await env.DB.prepare(`
    SELECT ss.role_id, r.name as role_name, r.description, r.role_date, r.start_time, r.end_time, e.name as event_name
    FROM signup_slots ss
    JOIN serve_roles r ON ss.role_id = r.id
    JOIN serve_events e ON r.event_id = e.id
    WHERE ss.signup_id = ?
  `).bind(signupId).all();

  const ical = generateIcal(signup, slots.results || []);
  return new Response(ical, {
    headers: {
      'Content-Type': 'text/calendar;charset=UTF-8',
      'Content-Disposition': `attachment; filename="tlc-volunteer-shifts.ics"`
    }
  });
}

function parseIcalTime(dateStr, timeStr) {
  // dateStr: "2026-12-04", timeStr: "9:00 AM"
  if (!dateStr || !timeStr) return null;
  const [y, mo, d] = dateStr.split('-');
  const parts = timeStr.trim().split(' ');
  const [hStr, mStr] = parts[0].split(':');
  const ampm = (parts[1] || '').toUpperCase();
  let h = parseInt(hStr, 10);
  const m = parseInt(mStr, 10);
  if (ampm === 'PM' && h !== 12) h += 12;
  if (ampm === 'AM' && h === 12) h = 0;
  return `${y}${mo}${d}T${String(h).padStart(2,'0')}${String(m).padStart(2,'0')}00`;
}

function generateIcal(signup, slots) {
  const lines = [
    'BEGIN:VCALENDAR', 'VERSION:2.0',
    'PRODID:-//Timothy Lutheran Church//Volunteer Sign-Up//EN',
    'CALSCALE:GREGORIAN', 'METHOD:PUBLISH',
    'X-WR-TIMEZONE:America/Chicago',
  ];
  for (const slot of slots) {
    const dtstart = parseIcalTime(slot.role_date, slot.start_time);
    const dtend   = parseIcalTime(slot.role_date, slot.end_time);
    if (!dtstart || !dtend) continue;
    const desc = (slot.description || '').replace(/\n/g,'\\n').replace(/,/g,'\\,');
    lines.push(
      'BEGIN:VEVENT',
      `UID:tlc-${signup.id}-${slot.role_id}@timothystl.org`,
      `DTSTART;TZID=America/Chicago:${dtstart}`,
      `DTEND;TZID=America/Chicago:${dtend}`,
      `SUMMARY:${slot.event_name} – ${slot.role_name}`,
      `DESCRIPTION:${desc}`,
      'LOCATION:Timothy Lutheran Church\\, 6704 Fyler Ave\\, St. Louis\\, MO 63139',
      `ORGANIZER;CN=Timothy Lutheran Church:mailto:office@timothystl.org`,
      'END:VEVENT'
    );
  }
  lines.push('END:VCALENDAR');
  return lines.join('\r\n');
}

// ── ADMIN LOGIN ───────────────────────────────────────────────────────
async function handleAdminLogin(req) {
  let body; try { body = await req.text(); } catch { body = ''; }
  const params = new URLSearchParams(body);
  if (params.get('password') === ADMIN_PASSWORD) {
    return new Response('', { status: 302, headers: { Location: '/admin', 'Set-Cookie': authCookieHeader() } });
  }
  return html(LOGIN_HTML.replace('<!--ERROR-->', '<p style="color:#c0392b;margin-bottom:1rem;">Incorrect password.</p>'));
}

// ── ADMIN API ─────────────────────────────────────────────────────────
async function handleAdminApi(req, env, url, method) {
  const seg = url.pathname.replace('/admin/api/', '');

  if (seg === 'signups' && method === 'GET') {
    const ministry = url.searchParams.get('ministry') || '';
    let q = 'SELECT s.*, e.name as event_name FROM signups s LEFT JOIN serve_events e ON s.event_id=e.id';
    const binds = [];
    if (ministry && ministry !== 'all') { q += ' WHERE s.ministry=?'; binds.push(ministry); }
    q += ' ORDER BY s.created_at DESC';
    const rows = await env.DB.prepare(q).bind(...binds).all();
    // Attach slot details
    const signups = [];
    for (const s of (rows.results || [])) {
      const slotRows = await env.DB.prepare(
        `SELECT r.name, r.role_date, r.start_time, r.end_time FROM signup_slots ss JOIN serve_roles r ON ss.role_id=r.id WHERE ss.signup_id=?`
      ).bind(s.id).all();
      signups.push({ ...s, slot_details: slotRows.results || [] });
    }
    return json({ signups });
  }

  if (seg.startsWith('signups/') && method === 'DELETE') {
    const id = parseInt(seg.split('/')[1]);
    await env.DB.prepare('DELETE FROM signup_slots WHERE signup_id=?').bind(id).run();
    await env.DB.prepare('DELETE FROM signups WHERE id=?').bind(id).run();
    return json({ ok: true });
  }

  if (seg === 'events' && method === 'GET') {
    const events = await env.DB.prepare('SELECT * FROM serve_events ORDER BY sort_order,event_date,id').all();
    const result = [];
    for (const ev of (events.results || [])) {
      const roles = await env.DB.prepare(
        'SELECT * FROM serve_roles WHERE event_id=? ORDER BY role_date,sort_order,id'
      ).bind(ev.id).all();
      const rolesWithFill = [];
      for (const role of (roles.results || [])) {
        const filled = await env.DB.prepare('SELECT COUNT(*) as n FROM signup_slots WHERE role_id=?').bind(role.id).first();
        rolesWithFill.push({ ...role, filled_count: filled?.n || 0 });
      }
      result.push({ ...ev, roles: rolesWithFill });
    }
    return json({ events: result });
  }

  if (seg === 'events' && method === 'POST') {
    let b; try { b = await req.json(); } catch { return json({ error: 'Invalid JSON' }, 400); }
    const r = await env.DB.prepare(
      'INSERT INTO serve_events (name,description,event_date,sort_order) VALUES (?,?,?,?)'
    ).bind(b.name||'New Event', b.description||'', b.event_date||'', b.sort_order||0).run();
    return json({ ok: true, id: r.meta?.last_row_id });
  }

  if (seg.startsWith('events/') && !seg.includes('/roles') && method === 'PUT') {
    const id = parseInt(seg.split('/')[1]);
    let b; try { b = await req.json(); } catch { return json({ error: 'Invalid JSON' }, 400); }
    await env.DB.prepare(
      'UPDATE serve_events SET name=?,description=?,event_date=?,hidden=?,sort_order=? WHERE id=?'
    ).bind(b.name, b.description||'', b.event_date||'', b.hidden?1:0, b.sort_order||0, id).run();
    return json({ ok: true });
  }

  if (seg.startsWith('events/') && !seg.includes('/roles') && method === 'DELETE') {
    const id = parseInt(seg.split('/')[1]);
    const roles = await env.DB.prepare('SELECT id FROM serve_roles WHERE event_id=?').bind(id).all();
    for (const r of (roles.results||[])) {
      await env.DB.prepare('DELETE FROM signup_slots WHERE role_id=?').bind(r.id).run();
    }
    await env.DB.prepare('DELETE FROM serve_roles WHERE event_id=?').bind(id).run();
    await env.DB.prepare('DELETE FROM serve_events WHERE id=?').bind(id).run();
    return json({ ok: true });
  }

  if (seg.match(/^events\/\d+\/roles$/) && method === 'POST') {
    const evId = parseInt(seg.split('/')[1]);
    let b; try { b = await req.json(); } catch { return json({ error: 'Invalid JSON' }, 400); }
    const r = await env.DB.prepare(
      'INSERT INTO serve_roles (event_id,name,description,slots,sort_order,role_date,start_time,end_time) VALUES (?,?,?,?,?,?,?,?)'
    ).bind(evId, b.name||'New Role', b.description||'', b.slots||0, b.sort_order||0,
           b.role_date||'', b.start_time||'', b.end_time||'').run();
    return json({ ok: true, id: r.meta?.last_row_id });
  }

  if (seg.match(/^events\/\d+\/roles\/\d+$/) && method === 'PUT') {
    const parts = seg.split('/'); const rid = parseInt(parts[3]);
    let b; try { b = await req.json(); } catch { return json({ error: 'Invalid JSON' }, 400); }
    await env.DB.prepare(
      'UPDATE serve_roles SET name=?,description=?,slots=?,sort_order=?,role_date=?,start_time=?,end_time=? WHERE id=?'
    ).bind(b.name, b.description||'', b.slots||0, b.sort_order||0,
           b.role_date||'', b.start_time||'', b.end_time||'', rid).run();
    return json({ ok: true });
  }

  if (seg.match(/^events\/\d+\/roles\/\d+$/) && method === 'DELETE') {
    const parts = seg.split('/'); const rid = parseInt(parts[3]);
    await env.DB.prepare('DELETE FROM signup_slots WHERE role_id=?').bind(rid).run();
    await env.DB.prepare('DELETE FROM serve_roles WHERE id=?').bind(rid).run();
    return json({ ok: true });
  }

  if (seg === 'export.csv' && method === 'GET') {
    const ministry = url.searchParams.get('ministry') || '';
    let q = 'SELECT s.*, e.name as event_name FROM signups s LEFT JOIN serve_events e ON s.event_id=e.id';
    const binds = [];
    if (ministry && ministry !== 'all') { q += ' WHERE s.ministry=?'; binds.push(ministry); }
    q += ' ORDER BY s.created_at DESC';
    const rows = await env.DB.prepare(q).bind(...binds).all();
    const cols = ['id','ministry','name','email','phone','roles','service','sundays','shirt_wanted','shirt_size','notes','event_name','created_at'];
    let csv = cols.join(',') + '\n';
    for (const r of (rows.results || [])) {
      csv += cols.map(c => {
        const v = r[c] == null ? '' : String(r[c]);
        return v.includes(',') || v.includes('"') || v.includes('\n') ? '"' + v.replace(/"/g,'""') + '"' : v;
      }).join(',') + '\n';
    }
    return new Response(csv, {
      headers: {
        'Content-Type': 'text/csv',
        'Content-Disposition': `attachment; filename="volunteers-${new Date().toISOString().slice(0,10)}.csv"`
      }
    });
  }

  return json({ error: 'Not found' }, 404);
}

